  'baby-blanket': { label: 'Bebek Battaniyesi', prompt: 'on a soft baby blanket on the nursery floor. Pastel colors.' },
  'baby-shelf': { label: 'Bebek Rafi', prompt: 'on a baby room wall shelf with small stuffed animals. Pastel decor.' },
  'kids-carpet': { label: 'Cocuk Halisi', prompt: 'on a colorful carpet in a bright childrens room. Toys in soft bokeh.' },
  'kids-playroom': { label: 'Oyun Alani', prompt: 'in a bright playroom surrounded by blurred colorful toys.' },
  'kids-desk': { label: 'Cocuk Masasi', prompt: 'on a childs desk with colorful pencils and books blurred.' },
