};

const SD = { 'simple': 'Very clean simple scene, minimal props.', 'medium': '', 'detailed': 'Rich detailed scene with many props and decorations.' };
const CD = { 'close': 'Close-up shot, toy fills most of frame.', 'medium': '', 'far': 'Wide shot showing full room, toy smaller in frame.' };
const TS = { 'small': 'Toy appears small in scene.', 'medium': '', 'large': 'Toy is prominently large in frame.' };
const CA = { 'front': 'Straight front view.', 'front-45': '45-degree front angle.', 'side': 'Side angle.', 'top': 'Top-down view.', 'low': 'Low angle looking up.' };
const TP = { 'keep': '', 'sitting': 'Toy in cute sitting position.', 'standing': 'Toy standing upright.', 'lying': 'Toy lying on its side.', 'tilted': 'Toy slightly tilted playfully.' };

const opts = webhookData.promptOptions || {};
const extraNotes = opts.extraNotes ? ' ' + opts.extraNotes : '';
const sett = webhookData.settings || {};
const promptRules = sett.promptRules || 'Keep the amigurumi toy EXACTLY as it is. Only change the background. Professional Etsy product photography.';
const concepts = webhookData.concepts || [];

// Build all prompts
const tasks = [];
for (const concept of concepts) {
  const bgId = concept.backgroundId;
  const variants = concept.variants || [concept.variant || {}];
  const preset = PRESETS[bgId];
  if (!preset) continue;
  for (let vi = 0; vi < variants.length; vi++) {
    const v = variants[vi];
    const variantParts = [SD[v.sceneDetail] || '', CD[v.cameraDistance] || '', TS[v.toySize] || '', CA[v.cameraAngle] || CA['front-45'], TP[v.toyPose] || ''].filter(Boolean).join(' ');
    const variationHint = variants.length > 1 ? ' Create a unique variation (variation ' + (vi+1) + ' of ' + variants.length + '), slightly different composition and exact placement.' : '';
    const fullPrompt = 'Edit this image: Remove the background and place the amigurumi toy ' + preset.prompt + ' ' + variantParts + ' ' + promptRules + variationHint + extraNotes;
    tasks.push({ prompt: fullPrompt, backgroundId: bgId, backgroundLabel: preset.label + (variants.length > 1 ? ' #' + (vi+1) : '') });
  }
}

if (tasks.length === 0) throw new Error('No valid concepts');

const sleep = (ms) => new Promise(resolve => setTimeout(resolve, ms));
const results = [];

for (let i = 0; i < tasks.length; i++) {
  if (i > 0) await sleep(6000); // 6 second delay between requests

  const task = tasks[i];
  try {
    const res = await fetch(GEMINI_URL, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        contents: [{ parts: [{ inlineData: { mimeType: 'image/png', data: base64Data.base64 } }, { text: task.prompt }] }],
        generationConfig: { responseModalities: ['IMAGE', 'TEXT'] }
      })
    });

    if (!res.ok) {
      console.log('Gemini error for ' + task.backgroundLabel + ': ' + res.status);
      continue;
    }

    const data = await res.json();
    let imageBase64 = null;
    const parts = data.candidates?.[0]?.content?.parts || [];
    for (const part of parts) {
      const idata = part.inlineData || part.inline_data;
      if (idata && idata.data) { imageBase64 = idata.data; break; }
    }

    if (!imageBase64) continue;

    const ts = Math.floor(Date.now() / 1000).toString();
    const folder = 'amigurumi/gemini';
    const sig = crypto.createHash('sha1').update('folder=' + folder + '&timestamp=' + ts + CLOUD_SECRET).digest('hex');
    results.push({ imageBase64, cloudTs: ts, cloudSig: sig, backgroundId: task.backgroundId, backgroundLabel: task.backgroundLabel });
  } catch(e) {
    console.log('Gemini fetch error for ' + task.backgroundLabel + ': ' + e.message);
  }
}

if (results.length === 0) {
  return [{ json: { noImages: true, productId: webhookData.productId, callbackUrl: webhookData.callbackUrl, secret: webhookData.secret, title, description, tags } }];
}

return results.map(r => ({ json: { ...r, title, description, tags, productId: webhookData.productId, callbackUrl: webhookData.callbackUrl, secret: webhookData.secret } }));

const images = [];
let title = '', description = '', tags = [], productId = '', callbackUrl = '', secret = '';

try {
  const uploadResults = $('Cloudinary Upload').all();
  const genItems = $('Generate Images').all().filter(i => !i.json.noImages);
  for (let i = 0; i < genItems.length; i++) {
    const gen = genItems[i].json;
    const upload = uploadResults[i]?.json;
    if (!productId) { title = gen.title || ''; description = gen.description || ''; tags = gen.tags || []; productId = gen.productId; callbackUrl = gen.callbackUrl; secret = gen.secret; }
    if (upload?.secure_url) { images.push({ url: upload.secure_url, backgroundId: gen.backgroundId, backgroundLabel: gen.backgroundLabel }); }
  }
} catch(e) {}

if (!callbackUrl) {
  const noImg = $('Generate Images').all().find(i => i.json.noImages);
  if (noImg) { callbackUrl = noImg.json.callbackUrl; secret = noImg.json.secret; productId = noImg.json.productId; title = noImg.json.title || ''; description = noImg.json.description || ''; tags = noImg.json.tags || []; }
}

return [{ json: { callbackUrl, callbackBody: { secret, type: 'generate-result', productId, images, title, description, tags } } }];
